package local.redcare.support;import java.util.LinkedHashMap;import java.util.Map;import java.util.Optional;public class Cache<K, V> {    private final Map<K, V> entries;    public Cache(int capacity) {        entries = new LruCache<>(capacity);    }    public synchronized Optional<V> lookUp(K key) {        return Optional.ofNullable(entries.get(key));    }    public synchronized void put(K key, V value) {        entries.put(key, value);    }    private static class LruCache<K, V> extends LinkedHashMap<K, V> {        private final int capacity;        public LruCache(int capacity) {            super(3 * capacity >>> 2 + 1, 0.75f, true);            this.capacity = capacity;        }        @Override        protected boolean removeEldestEntry(Map.Entry<K, V> eldest) {            return size() > capacity;        }    }}